// // This module synchronizes the input signal 'in' to the output 'out' on the falling edge of the clock 'clk', but only updates 'out' when 'en' is low.
module top_module(clk, en, in, out) ;parameter n = 16;  
  input clk, en ;
  input  [n-1:0] in ;
  output [n-1:0] out ;
  reg    [n-1:0] out ;
  wire   [n-1:0] next_out ;

  assign next_out = en ? in : out;

  always @(posedge clk)
    out = next_out;endmodule
